class Solution {
public:
    int pivotIndex(vector<int>& nums) {
        long long left = 0, right = accumulate(nums.begin(), nums.end(), 0LL);
        for (int i = 0; i < (int)nums.size(); i++) {
            right -= nums[i];
            if (left == right) return i;
            left += nums[i];
        }
        return -1;
    }
};

