int pivotIndex(int* nums, int n) {
    long long left = 0, right = 0;
    for (int i = 0; i < n; i++) right += nums[i];
    for (int i = 0; i < n; i++) {
        right -= nums[i];
        if (left == right) return i;
        left += nums[i];
    }
    return -1;
}
